#!/usr/bin/env node
// QA Council - School Goal Modal Checks
// Generated by The Engineer (Agent 3). Tests for school builder goal modal elements.
// Usage: node school-goal-modal-checks.js

var fs = require('fs');
var path = require('path');

var CONFIG = {
  basePath: '/sessions/sleepy-gifted-allen/mnt/site/strategic-school',
  htmlFile: 'index.html',
  jsFile: 'js/school.js'
};

var results = [];
var passed = 0;
var failed = 0;

function assert(condition, testName, details) {
  if (condition) {
    console.log('[PASS] ' + testName);
    passed++;
  } else {
    console.log('[FAIL] ' + testName + (details ? ': ' + details : ''));
    failed++;
  }
  results.push({ test: testName, passed: condition, details: details || '' });
}

// ============================================================================
// TEST 1: Check Static HTML Elements for Hierarchical Goal Builder
// ============================================================================
function testStaticHtmlElements() {
  console.log('\n--- Static HTML Elements (Hierarchical Goal Builder) ---');

  var htmlPath = path.join(CONFIG.basePath, CONFIG.htmlFile);
  if (!fs.existsSync(htmlPath)) {
    assert(false, 'index.html exists', 'File not found');
    return;
  }

  var htmlContent = fs.readFileSync(htmlPath, 'utf8');

  // Expected container for the new hierarchical goal builder
  var expectedContainers = [
    { id: 'goalsContainer', desc: 'Goals container for hierarchical goal builder' }
  ];

  var foundInHtml = [];
  var missingFromHtml = [];

  expectedContainers.forEach(function(item) {
    if (htmlContent.includes('id="' + item.id + '"') || htmlContent.includes("id='" + item.id + "'")) {
      foundInHtml.push(item.id);
      assert(true, 'HTML contains: ' + item.id);
    } else {
      missingFromHtml.push(item.id);
      assert(false, 'HTML contains: ' + item.id, item.desc + ' (static)');
    }
  });

  console.log('\nStatic HTML Summary: ' + foundInHtml.length + '/' + expectedContainers.length + ' found\n');
}

// ============================================================================
// TEST 2: Check Dynamic Element Creation for Hierarchical Goal Builder
// ============================================================================
function testDynamicElementCreation() {
  console.log('\n--- Dynamic Element Creation (Hierarchical) ---');

  var jsPath = path.join(CONFIG.basePath, CONFIG.jsFile);
  if (!fs.existsSync(jsPath)) {
    assert(false, 'school.js exists', 'File not found');
    return;
  }

  var jsContent = fs.readFileSync(jsPath, 'utf8');

  // Check for goalsContainer usage in the hierarchical builder
  var patterns = [
    new RegExp('getElementById\\(["\']goalsContainer["\']'),  // getElementById('goalsContainer')
    new RegExp('goalsContainer["\']'),                          // references to goalsContainer
  ];

  var found = patterns.some(function(pattern) {
    return pattern.test(jsContent);
  });

  if (found) {
    assert(true, 'JS uses goalsContainer for hierarchical builder');
  } else {
    assert(false, 'JS uses goalsContainer for hierarchical builder', 'Container reference not found');
  }

  console.log('');
}

// ============================================================================
// TEST 3: Check for Hierarchical Goal Builder Functions
// ============================================================================
function testModalFunctions() {
  console.log('\n--- Hierarchical Goal Builder Functions ---');

  var jsPath = path.join(CONFIG.basePath, CONFIG.jsFile);
  var jsContent = fs.readFileSync(jsPath, 'utf8');

  // Expected hierarchical goal builder functions
  var builderFunctions = [
    { name: 'renderGoalAreaPlans', desc: 'Render goal area plans' },
    { name: 'addGoalArea', desc: 'Add a new goal area' },
    { name: 'addProblemStatement', desc: 'Add problem statement' },
    { name: 'addGoal', desc: 'Add a goal within problem statement' },
    { name: 'addAPO', desc: 'Add Annual Performance Objective' },
    { name: 'addStrategy', desc: 'Add strategy' },
    { name: 'saveGoalField', desc: 'Save individual goal field' }
  ];

  var foundFunctions = [];
  var missingFunctions = [];

  builderFunctions.forEach(function(fn) {
    var patterns = [
      new RegExp('function\\s+' + fn.name + '\\s*\\('),
      new RegExp('var\\s+' + fn.name + '\\s*=\\s*function'),
      new RegExp(fn.name + '\\s*:\\s*function'),
      new RegExp('window\\.' + fn.name + '\\s*=')
    ];

    var found = patterns.some(function(pattern) {
      return pattern.test(jsContent);
    });

    if (found) {
      foundFunctions.push(fn.name);
      assert(true, 'Function exists: ' + fn.name);
    } else {
      missingFunctions.push(fn.name);
      assert(false, 'Function exists: ' + fn.name, fn.desc);
    }
  });

  console.log('\nHierarchical Functions Summary: ' + foundFunctions.length + '/' + builderFunctions.length + ' found\n');
}

// ============================================================================
// TEST 4: Goal Area Plan Structure References
// ============================================================================
function testFormFieldReferences() {
  console.log('\n--- Goal Area Plan Structure ---');

  var jsPath = path.join(CONFIG.basePath, CONFIG.jsFile);
  var jsContent = fs.readFileSync(jsPath, 'utf8');

  // Check that goalAreaPlans structure is referenced in the state
  var hasGoalAreaPlans = jsContent.includes('goalAreaPlans') || jsContent.includes('planState.goalAreaPlans');
  assert(hasGoalAreaPlans, 'planState.goalAreaPlans structure used for goals');

  // Check for problem statements reference
  var hasProblemStatements = jsContent.includes('problemStatements') || jsContent.includes('problemStatement');
  assert(hasProblemStatements, 'Problem statements in goal structure');

  console.log('');
}

// ============================================================================
// TEST 5: Modal Display/Hide Logic
// ============================================================================
function testModalLogic() {
  console.log('\n--- Modal Display Logic ---');

  var jsPath = path.join(CONFIG.basePath, CONFIG.jsFile);
  var jsContent = fs.readFileSync(jsPath, 'utf8');

  // Check for modal display patterns
  var hasDisplayLogic = (
    (jsContent.includes('display') || jsContent.includes('show') || jsContent.includes('hidden')) &&
    (jsContent.includes('modal') || jsContent.includes('Modal'))
  );

  assert(hasDisplayLogic, 'Modal display logic present', 'Looking for show/hide functionality');

  // Check for event listeners or click handlers
  var hasEventHandlers = (
    jsContent.includes('addEventListener') ||
    jsContent.includes('onclick') ||
    jsContent.includes('on(')
  );

  assert(hasEventHandlers, 'Event handlers for modal interaction present');

  // Check for data storage/retrieval
  var hasDataHandling = (
    jsContent.includes('localStorage') ||
    jsContent.includes('sessionStorage') ||
    jsContent.includes('planState') ||
    jsContent.includes('goalData')
  );

  assert(hasDataHandling, 'Data storage/retrieval logic present');
}

// ============================================================================
// RUN ALL TESTS
// ============================================================================
console.log('\n======================================');
console.log('QA Council: School Goal Modal Checks');
console.log('======================================');
console.log('Base Path: ' + CONFIG.basePath);
console.log('Testing hierarchical goal builder');
console.log('');

testStaticHtmlElements();
testDynamicElementCreation();
testModalFunctions();
testFormFieldReferences();
testModalLogic();

console.log('\n======================================');
console.log('Results: ' + passed + ' passed, ' + failed + ' failed');
console.log('======================================\n');

// Write results to JSON
var outputPath = path.join(path.dirname(process.argv[1]), 'goal-modal-results.json');
fs.writeFileSync(outputPath, JSON.stringify({
  target: 'school-builder-goals',
  timestamp: new Date().toISOString(),
  passed: passed,
  failed: failed,
  total: passed + failed,
  builderType: 'hierarchical',
  results: results
}, null, 2));

console.log('Results written to: goal-modal-results.json');
process.exit(failed > 0 ? 1 : 0);
